class PolicyConfig(pydantic.BaseModel):
    """Scientist-editable policy package.

    Values are latent implementation capacities/probabilities. Employee and
    manager agents see only realized events and finite envelopes generated by
    Python. ``label`` and ``hypothesis`` are never included in agent prompts.
    """

    label: str = "synthetic_stressed_reference_v2"
    hypothesis: str = (
        "Human-authored stressed synthetic reference; not a calibrated claim about Japan."
    )

    # Department-level external capacity; never interpreted as personal support.
    staffing_buffer: UnitInterval = 0.0
    workload_triage_support: UnitInterval = 0.03
    manager_support: UnitInterval = 0.08
    management_case_capacity: Annotated[int, pydantic.Field(ge=4, le=12)] = 6
    explanation_quality: UnitInterval = 0.08
    preference_matching: UnitInterval = 0.10
    learning_access_probability: UnitInterval = 0.01
    protected_learning_share: UnitInterval = 0.03
    digital_support: UnitInterval = 0.03
    process_reform_support: UnitInterval = 0.02
    specialist_track_access: UnitInterval = 0.02
    appeal_channel: UnitInterval = 0.01

    hiring_fill_rate: UnitInterval = 0.15
    hiring_capacity_rate: Annotated[float, pydantic.Field(ge=0.0, le=0.20)] = 0.02
    midcareer_hire_share: UnitInterval = 0.20
    transfer_capacity_rate: Annotated[float, pydantic.Field(ge=0.0, le=0.10)] = 0.012
    involuntary_transfer_share: UnitInterval = 0.75
    transfer_explanation_quality: UnitInterval = 0.08

    productivity_savings_capture: UnitInterval = 0.55

    @classmethod
    def baseline(cls) -> "PolicyConfig":
        return cls()


class WorkMix(pydantic.BaseModel):
    """Allocation of the non-protected remainder; exact total must be 100."""

    core_delivery_pct: Pct
    coordination_pct: Pct
    learning_pct: Pct
    process_improvement_pct: Pct

    @pydantic.model_validator(mode="after")
    def total_is_100(self) -> "WorkMix":
        total = (
            self.core_delivery_pct
            + self.coordination_pct
            + self.learning_pct
            + self.process_improvement_pct
        )
        if total != 100:
            raise ValueError(f"work mix must total 100, got {total}")
        return self


class MonthlySelfReport(pydantic.BaseModel):
    """Sealed LLM survey output used only for evaluation.

    These perceptions are never written to future prompt memory and never drive
    management priority, exits, staffing, task allocation, or any transition.
    They are not objective ground truth or independent human evidence.
    """

    fatigue_pct: Pct
    turnover_intent_pct: Pct
    organizational_trust_pct: Pct
    procedural_fairness_pct: Pct
    # Exploratory survey items. They stay outside all causal transitions and
    # are reported separately from the preregistered welfare selection channel.
    ebpm_interest_pct: Pct = 50
    dx_improvement_interest_pct: Pct = 50


class TransferPreference(pydantic.BaseModel):
    """Structured hand-raised preference; no free-text skill matching."""

    preferred_department: DepartmentName
    acceptable_departments: Annotated[
        list[DepartmentName], pydantic.Field(min_length=1, max_length=4)
    ]
    preferred_fields: Annotated[list[FieldName], pydantic.Field(min_length=1, max_length=3)]
    priority: Literal[
        "work_content",
        "career_growth",
        "workload_recovery",
        "family_and_location",
        "general",
    ]

    @pydantic.model_validator(mode="after")
    def validate_preferences(self) -> "TransferPreference":
        if self.preferred_department not in self.acceptable_departments:
            raise ValueError("preferred_department must be included in acceptable_departments")
        if len(set(self.acceptable_departments)) != len(self.acceptable_departments):
            raise ValueError("acceptable_departments must not contain duplicates")
        if len(set(self.preferred_fields)) != len(self.preferred_fields):
            raise ValueError("preferred_fields must not contain duplicates")
        return self


class BureaucratMonthlyAction(pydantic.BaseModel):
    """One environment-advancing monthly employee action."""

    relative_effort_pct: EffortPct
    work_mix: WorkMix
    work_response: WorkResponse
    voice_action: VoiceAction
    career_action: CareerAction
    transfer_preference: TransferPreference | None = None
    self_report: MonthlySelfReport
    event_refs: Annotated[list[str], pydantic.Field(min_length=1, max_length=8)]
    reason: Annotated[str, pydantic.Field(min_length=8)]
    next_month_intent: Annotated[str, pydantic.Field(min_length=5)]
    confidence: UnitInterval

    @pydantic.model_validator(mode="after")
    def semantic_consistency(self) -> "BureaucratMonthlyAction":
        effort = self.relative_effort_pct
        response = self.work_response
        if response == "work_overtime" and effort < 100:
            raise ValueError("work_overtime requires relative_effort_pct >= 100")
        if effort > 120 and response != "work_overtime":
            raise ValueError("relative_effort_pct > 120 requires explicit work_overtime")
        if response == "take_health_leave" and effort > 60:
            raise ValueError("take_health_leave requires relative_effort_pct <= 60")
        if response == "caregiving_leave" and effort > 70:
            raise ValueError("caregiving_leave requires relative_effort_pct <= 70")
        if response == "protect_health_capacity" and effort > 85:
            raise ValueError("protect_health_capacity requires relative_effort_pct <= 85")
        if response == "refuse_overtime" and effort > 100:
            raise ValueError("refuse_overtime requires relative_effort_pct <= 100")
        if self.career_action == "request_transfer" and self.transfer_preference is None:
            raise ValueError("request_transfer requires transfer_preference")
        if self.career_action != "request_transfer" and self.transfer_preference is not None:
            raise ValueError("transfer_preference is allowed only with request_transfer")
        return self


