class AgentProfile(pydantic.BaseModel):
    slot_id: int
    person_id: str
    identity_epoch: int
    department: DepartmentName
    rank: Literal["junior", "mid", "senior"]
    years_service: int
    field: FieldName
    employment_track: Literal["policy_generalist", "administrative_generalist", "specialist"]
    career_orientation: Literal["generalist", "specialist", "managerial", "mixed"]
    authority_scope: Literal["staff", "team_lead", "section_support"]
    family_constraint: UnitInterval
    public_service_motivation: UnitInterval
    autonomy_need: UnitInterval
    external_market_pull: UnitInterval
    transfer_aversion: UnitInterval
    baseline_capacity_units: Annotated[float, pydantic.Field(gt=0.0)]
    initial_skill_stock: Annotated[float, pydantic.Field(ge=0.5, le=1.5)]

    @staticmethod
    def _band(value: float) -> str:
        return "high" if value >= 0.67 else "moderate" if value >= 0.34 else "low"

    def prompt_summary(self) -> str:
        return (
            "You are a career civil servant in a synthetic Japanese central-government-style "
            "organization. You face formal approval chains, periodic personnel rotation, "
            "parliamentary/ministerial requests, statutory deadlines, and strong continuity duties. "
            "Do not behave as a private-company employee with unrestricted discretion. "
            f"department={self.department}; rank={self.rank}; years_service={self.years_service}; "
            f"employment_track={self.employment_track}; authority_scope={self.authority_scope}; "
            f"professional_field={self.field}; career_orientation={self.career_orientation}; "
            f"family_or_caregiving_constraints={self._band(self.family_constraint)}; "
            f"public_service_motivation={self._band(self.public_service_motivation)}; "
            f"career_autonomy_preference={self._band(self.autonomy_need)}; "
            f"external_opportunity_exposure={self._band(self.external_market_pull)}"
        )


