class BureaucracyMessage(Message):
    kind: str = "environment"
    content: str = ""


class BureaucracyObservation(Observation[BureaucracyMessage]):
    phase: Literal["monthly_action", "quarterly_reflection"]
    month: int
    identity_epoch: int
    profile_summary: str
    department_summary: str
    personal_objective_summary: str
    recent_events: list[WorkEvent]

    def allowed_event_ids(self) -> list[str]:
        return [event.event_id for event in self.recent_events]

    def format_as_prompt_text(self) -> str:
        events = "\n".join(
            f"- {event.event_id}: {event.description} "
            f"[realized_workload_ratio={event.objective_workload_ratio:.2f}; "
            f"after_hours_severity={event.after_hours_severity}; "
            f"involuntary={str(event.involuntary).lower()}]"
            for event in self.recent_events
        )
        phase_instruction = (
            "Return the monthly structured action. Interpret 100 effort as your own normal baseline; "
            "do not estimate absolute hours or department-wide output."
            if self.phase == "monthly_action"
            else "Return a concise quarterly reflection grounded in listed event IDs."
        )
        return (
            "Respond as the official described below. Do not mention experiments, source documents, "
            "policy labels, hidden variables, or expected treatment effects. Use only your profile, "
            "workplace facts, realized events, and bounded memory.\n\n"
            f"MONTH: {self.month}\nPHASE: {self.phase}\n"
            f"PROFILE: {self.profile_summary}\n"
            f"DEPARTMENT: {self.department_summary}\n"
            f"PERSONAL WORK RECORD: {self.personal_objective_summary}\n"
            f"EXPERIENCED EVENTS:\n{events}\n\n"
            f"{phase_instruction}\n"
            "Every event_refs value must exactly match an event ID above."
        )


class ManagerObservation(Observation[BureaucracyMessage]):
    phase: Literal["manager_decision"] = "manager_decision"
    month: int
    identity_epoch: int = 0
    department: DepartmentName
    department_fact_summary: str
    request_docket: Annotated[list[ManagementRequest], pydantic.Field(max_length=12)]
    support_envelope_units: Annotated[float, pydantic.Field(ge=0.0)]
    triage_envelope_units: Annotated[float, pydantic.Field(ge=0.0)]
    reform_slots: Annotated[int, pydantic.Field(ge=0, le=6)]
    explanation_slots: Annotated[int, pydantic.Field(ge=0, le=6)]
    specialist_slots: Annotated[int, pydantic.Field(ge=0, le=6)]

    def allowed_request_ids(self) -> list[str]:
        return [request.request_id for request in self.request_docket]

    def format_as_prompt_text(self) -> str:
        docket = "\n".join(
            f"- {r.request_id}: kind={r.request_kind}; priority={r.priority_score:.2f}; "
            f"requested_units={r.requested_units:.6f}; facts={r.fact_summary}"
            for r in self.request_docket
        ) or "- no employee request reached the privacy-minimized docket"
        return (
            "You are the section-level manager for one department in a synthetic Japanese "
            "central-government-style organization. You do not add capacity yourself. Decide only "
            "within the finite envelopes below. Separate a courteous public message from the "
            "resource commitment. Do not mention experiments, policy labels, hidden variables, or "
            "unlisted employees.\n\n"
            f"MONTH: {self.month}\nDEPARTMENT: {self.department}\n"
            f"FACTS: {self.department_fact_summary}\n"
            f"SUPPORT ENVELOPE UNITS: {self.support_envelope_units:.6f}\n"
            f"TRIAGE ENVELOPE UNITS: {self.triage_envelope_units:.6f}\n"
            f"REFORM SLOTS: {self.reform_slots}\nEXPLANATION SLOTS: {self.explanation_slots}\nSPECIALIST SLOTS: {self.specialist_slots}\n"
            f"DOCKET (configured finite representative request list):\n{docket}\n\n"
            "Return exactly one decision for each listed request ID. A message without committed "
            "units is not support. Rejected or deferred requests create no effect."
        )


class MonthlyAgentRecord(pydantic.BaseModel):
    month: int
    slot_id: int
    person_id: str
    identity_epoch: int
    initial_cohort: bool
    department: DepartmentName
    action: BureaucratMonthlyAction
    assigned_work_ratio: float
    actual_completed_units: float
    actual_completion_ratio: Annotated[float, pydantic.Field(ge=0.0)]
    work_strain_pressure_before: float
    work_strain_pressure_after: float
    skill_after: float
    modernization_after: float
    effective_core_share: UnitInterval = 0.0
    effective_coordination_share: UnitInterval = 0.0
    effective_learning_share: UnitInterval = 0.0
    effective_process_share: UnitInterval = 0.0
    protected_learning_share: UnitInterval = 0.0
    individual_support_ratio: UnitInterval = 0.0
    exited_this_month: bool
    exit_reason: ExitReason | None = None


class StaffingEvent(pydantic.BaseModel):
    month: int
    event_type: Literal["exit", "hire", "voluntary_transfer", "involuntary_transfer"]
    slot_id: int
    person_id: str
    from_department: DepartmentName | None = None
    to_department: DepartmentName | None = None
    exit_reason: ExitReason | None = None
    details: str


class TransferPlanRecord(pydantic.BaseModel):
    month: int
    slot_id: int
    person_id: str
    from_department: DepartmentName
    to_department: DepartmentName
    voluntary: bool
    request_id: str | None = None
    total_score: float
    pressure_gain: float
    field_fit: float
    preference_fit: float
    family_cost: float
    transfer_aversion_cost: float


class PolicyLabResult(pydantic.BaseModel):
    summary: dict[str, float | int | str | None]
    profiles: list[AgentProfile]
    monthly_records: list[MonthlyAgentRecord]
    department_rows: list[dict[str, float | int | str | None]]
    staffing_events: list[StaffingEvent]
    transfer_plans: list[TransferPlanRecord]
    transfer_requests: list[TransferRequestRecord] = []
    management_outcomes: list[RealizedManagementOutcome]
    exposure_events: list[ExposureEvent] = []
    task_rows: list[TaskLedgerRow] = []
    reflections: list[dict[str, object]]
